async (params, browser) => {
  // Open Jira
  await browser.open(`${params.jira_url}/browse`)

  // Let Jira load
  await browser.wait(2000)

  // Create issue via REST API
  const result = await browser.evaluate(`const baseUrl = params.jira_url.replace(/\/$/, ''); const desc = params.description; const body = { fields: { project: { key: params.project_key }, summary: params.summary, issuetype: { name: params.issue_type || 'Task' } } }; if (desc) { body.fields.description = { type: 'doc', version: 1, content: [{ type: 'paragraph', content: [{ type: 'text', text: desc }] }] }; } const priority = params.priority; if (priority) { body.fields.priority = { name: priority }; } const resp = await fetch(baseUrl + '/rest/api/3/issue', { method: 'POST', headers: { 'Content-Type': 'application/json' }, credentials: 'same-origin', body: JSON.stringify(body) }); if (!resp.ok) { const err = await resp.text(); throw new Error('Create failed: ' + resp.status + ' ' + err); } const result = await resp.json(); return { success: true, key: result.key, id: result.id, url: baseUrl + '/browse/' + result.key }`)

  return result
}
